using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPhonePattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Adams", "Prof.");

        Assert.Contains("Prof.", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  My Blog Post  ", "my-blog-post")]
    [DataRow("C# & .NET Tips!", "c-net-tips")]
    [DataRow("already-lowercase", "already-lowercase")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        Assert.AreEqual(expected, _formatter.GenerateSlug(title));
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ProducesLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.MatchesRegex(@"^[a-z0-9-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialChars_DoesNotStartOrEndWithDash()
    {
        var result = _formatter.GenerateSlug("--Hello World--");

        Assert.That.StartsWith("h", result);
        Assert.That.EndsWith("d", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWith00()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(9.5m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
        Assert.AreEqual("$9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }
}

